import { mergeProps } from "@base-ui/react/merge-props";
import { useRender } from "@base-ui/react/use-render";
import * as stylex from "@stylexjs/stylex";
import type React from "react";
import { colorStyles } from "@/utils/base.styles";
import type { PropsWithStylex } from "@/utils/stylex.utils";
import {
	fontSizeStyles,
	textAlignStyles,
	textStyles,
	textTransformStyles,
	textVarianttyles,
	textWeightStyles,
} from "./text.styles";
import { Box, type BoxProps } from "../Box/box";

const variantTag = {
	h1: "h1",
	h2: "h2",
	h3: "h3",
	h4: "h4",
	h5: "h5",
	h6: "h6",
	body1: "div",
	body2: "div",
	body3: "div",
	body4: "div",
	caption: "div",
	creatorNote: "p",
	p: "p",
	code: "code",
} as const satisfies Record<string, keyof React.JSX.IntrinsicElements>;
export type TextVariant = keyof typeof variantTag;

type Props = PropsWithStylex<
	BoxProps & {
		variant?: TextVariant;
		color?: keyof typeof colorStyles;
		align?: keyof typeof textAlignStyles;
		weight?: keyof typeof textWeightStyles;
		transform?: keyof typeof textTransformStyles;
		size?: keyof typeof fontSizeStyles;
		style?: stylex.StyleXStyles;
		span?: boolean;
	}
>;

export function Text({
	variant = "body1",
	color,
	align,
	weight,
	style,
	size,
	render,
	span,
	transform = "none",
	...props
}: Props): React.ReactElement {
	const sx = stylex.props(
		textStyles.base,
		textTransformStyles[transform],
		textVarianttyles[variant],
		color && colorStyles[color],
		align && textAlignStyles[align],
		weight && textWeightStyles[weight],
		!color && colorStyles.primary,
		size && fontSizeStyles[size],
		style,
	);
	const merged = mergeProps(props, sx);
	if (span) {
		return useRender({
			defaultTagName: "span",
			props: merged,
			render,
		});
	}
	return <Box render={render} {...merged} />;
}

import * as stylex from "@stylexjs/stylex";
import { theme } from "@/lib/theme/contract.stylex";
import {
	borderRadius,
	fontSize,
	fonts,
	fontWeight,
	letterSpacing,
	lineHeight,
	spacing,
} from "@/lib/theme/tokens.stylex";

export const textTransformStyles = stylex.create({
	uppercase: {
		textTransform: "uppercase",
	},
	capitalize: {
		textTransform: "capitalize",
	},
	none: {
		textTransform: "none",
	},
	lowercase: {
		textTransform: "lowercase",
	},
});

export const textAlignStyles = stylex.create({
	left: { textAlign: "left" },
	center: { textAlign: "center" },
	right: { textAlign: "right" },
});
export const fontSizeStyles = stylex.create({
	xxsmall: { fontSize: spacing.xxsmall, lineHeight: lineHeight.tight },
	xsmall: { fontSize: spacing.xsmall, lineHeight: lineHeight.tight },
	small: { fontSize: spacing.small, lineHeight: lineHeight.tight },
	medium: { fontSize: spacing.medium, lineHeight: lineHeight.tight },
	large: { fontSize: spacing.large, lineHeight: lineHeight.tight },
	xlarge: { fontSize: spacing.xlarge, lineHeight: lineHeight.tight },
	xxlarge: { fontSize: spacing.xxlarge, lineHeight: lineHeight.tight },
	xxxlarge: { fontSize: spacing.xxxlarge, lineHeight: lineHeight.tight },
	huge: { fontSize: spacing.huge, lineHeight: lineHeight.tight },
	massive: { fontSize: spacing.massive, lineHeight: lineHeight.tight },
	titanic: { fontSize: spacing.titanic, lineHeight: lineHeight.tight },
});

export const textWeightStyles = stylex.create({
	regular: { fontWeight: fontWeight.regular },
	medium: { fontWeight: fontWeight.medium },
	semibold: { fontWeight: fontWeight.semibold },
	bold: { fontWeight: fontWeight.bold },
});
export const textStyles = stylex.create({
	base: {
		margin: 0,
		textDecoration: "none",
		color: theme.contentAccent,
	},
});
export const textVarianttyles = stylex.create({
	h1: {
		fontFamily: fonts.display,
		fontSize: fontSize.display,
		lineHeight: lineHeight.tight,
		fontWeight: fontWeight.bold,
		letterSpacing: letterSpacing.tight,
		margin: 0,
	},
	h2: {
		fontFamily: fonts.heading,
		fontSize: fontSize.xxlarge,
		lineHeight: lineHeight.tight,
		fontWeight: fontWeight.bold,
		letterSpacing: letterSpacing.tight,
		margin: 0,
	},
	h3: {
		fontFamily: fonts.heading,
		fontSize: fontSize.xlarge,
		lineHeight: lineHeight.snug,
		fontWeight: fontWeight.semibold,
		letterSpacing: letterSpacing.snug,
		margin: 0,
	},
	h4: {
		fontFamily: fonts.heading,
		fontSize: fontSize.large,
		lineHeight: lineHeight.tight,
		fontWeight: fontWeight.semibold,
		margin: 0,
	},
	h5: {
		fontFamily: fonts.heading,
		fontSize: fontSize.medium,
		lineHeight: lineHeight.normal,
		fontWeight: fontWeight.semibold,
		margin: 0,
	},
	h6: {
		fontFamily: fonts.heading,
		fontSize: fontSize.small,
		lineHeight: lineHeight.normal,
		fontWeight: fontWeight.semibold,
		margin: 0,
	},
	body1: {
		fontFamily: fonts.body,
		fontSize: fontSize.medium,
		lineHeight: lineHeight.normal,
		fontWeight: fontWeight.regular,
		margin: 0,
	},
	body2: {
		fontFamily: fonts.body,
		fontSize: fontSize.small,
		lineHeight: lineHeight.normal,
		fontWeight: fontWeight.regular,
		margin: 0,
	},
	body3: {
		fontFamily: fonts.body,
		fontSize: fontSize.xsmall,
		lineHeight: lineHeight.normal,
		fontWeight: fontWeight.regular,
		margin: 0,
	},
	body4: {
		fontFamily: fonts.label,
		fontSize: fontSize.xxsmall,
		lineHeight: lineHeight.normal,
		fontWeight: fontWeight.medium,
		letterSpacing: letterSpacing.wide,
		margin: 0,
	},
	caption: {
		fontFamily: fonts.label,
		fontSize: fontSize.xsmall,
		lineHeight: lineHeight.normal,
		fontWeight: fontWeight.medium,
		letterSpacing: letterSpacing.wide,
		margin: 0,
	},
	creatorNote: {
		fontFamily: fonts.body,
		fontSize: fontSize.large,
		lineHeight: "28px",
		fontWeight: fontWeight.regular,
		fontStyle: "italic",
		margin: 0,
	},
	p: {
		fontFamily: fonts.body,
		fontSize: fontSize.medium,
		lineHeight: lineHeight.normal,
		fontWeight: fontWeight.regular,
		margin: 0,
	},
	div: {
		fontFamily: fonts.body,
		fontSize: fontSize.medium,
		lineHeight: lineHeight.normal,
		fontWeight: fontWeight.regular,
		margin: 0,
	},
	code: {
		fontFamily: fonts.mono,
		fontSize: fontSize.small,
		lineHeight: lineHeight.normal,
		fontWeight: fontWeight.regular,
		margin: 0,
		backgroundColor: theme.backgroundSubtle,
		padding: spacing["1"],
		borderRadius: borderRadius.small,
	},
});
